class Solution(object):
    def circularArrayLoop(self, nums):
        n = len(nums)
        for i in range(n):
            visited = set()
            slow = i
            while slow not in visited:
                visited.add(slow)
                slow = (slow + nums[slow]) % n
            if slow in visited and len(visited) > 1:
                cycle_start = slow
                cycle_len = 0
                current = slow
                while True:
                    current = (current + nums[current]) % n
                    cycle_len += 1
                    if current == slow:
                        break
                if cycle_len > 1:
                    direction = nums[cycle_start] > 0
                    valid = True
                    current = cycle_start
                    for _ in range(cycle_len):
                        if (nums[current] > 0) != direction:
                            valid = False
                            break
                        current = (current + nums[current]) % n
                    if valid:
                        return True
        return False
